INSERT INTO public.questions(category_id, language_code, prompt, option_a, option_b, option_c, option_d, correct_option, explanation, explanation_ku, explanation_tr, difficulty, is_approved, question_type, image_url, source_url, source_reference)
SELECT n.*
FROM new_rows n
WHERE NOT EXISTS (
  SELECT 1 FROM public.questions q
  WHERE q.prompt = n.prompt AND q.category_id = n.category_id
);

WITH new_rows(category_id, language_code, prompt, option_a, option_b, option_c, option_d, correct_option, explanation, explanation_ku, explanation_tr, difficulty, is_approved, question_type, image_url, source_url, source_reference) AS (
  VALUES
    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', 'Di vegotina Newrozê de sembola berxwedana li dijî zalim kî ye?', 'Şeref Han Bitlisi', 'Kawa/Kave Demirci', 'Beylik (mîrlik)', 'Irak Cumhurbaşkanı', 'B', 'Kürt Newroz anlatısında Kawa, Dehak/Zahhak zulmüne karşı başkaldırının sembol figürüdür.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2227'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Kurmancî û Soranî wek du zaravayên girîng ên çi têne zanîn?', 'Kürtçe', 'Arapça', 'Yunanca', 'Rusça', 'A', 'Kurmancî ve Soranî, Kürtçe denildiğinde en yaygın iki ana lehçe/standart olarak öne çıkar.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2231'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Kurmancî bi piranî bi kîjan pergala nivîsandinê tê nivîsandin?', 'Latin kökenli Hawar alfabesi', 'Kiril alfabesi dışında hiçbir alfabe', 'Çivi yazısı', 'Japon kana sistemi', 'A', 'Kurmancî, özellikle Türkiye ve Suriye bağlamında Latin temelli Hawar alfabesiyle yaygınlaşmıştır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2232'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Soranî li Iraq û Îranê bi piranî bi kîjan pergala nivîsê tê nivîsandin?', 'Arap temelli Kürt alfabesi', 'Latin Hawar alfabesi dışında hiç yazılmaz', 'Runik yazı', 'Gürcü alfabesi', 'A', 'Soranî, Irak ve İran’da Arap temelli Kürt alfabesiyle yaygın biçimde yazılır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2233'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Di kurdî de peyva “heval” bi giştî tê çi wateyê?', 'Arkadaş/yoldaş', 'teşekkürler', 'Erkek kardeş', 'Gelecek zaman', 'A', 'Heval, gündelik kullanımda arkadaş; siyasal-kolektif bağlamda yoldaş anlamında kullanılır.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2237'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Di xebatên naskirina axaftina kurdî de projeya Jira di kîjan qadê de wek mînak tê nîşandan?', 'Kullanıcı seviyesine göre soru seçmeyi', 'Temel sözvarlığı ve kültürel kavramları tanıma', 'Kategori, seçenek, doğru cevap ve açıklama içeren yapı', 'Merkezî Kürtçe/Soranî için konuşma korpusu ve tanıma sistemi', 'D', 'Jira, Merkezî Kürtçe için konuşma korpusu ve büyük sözvarlıklı konuşma tanıma çalışması olarak sunulmuştur.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2241'),
    ('88cb52dd-ad38-4740-bdd7-df64ef84bc44'::uuid, 'ku-kmr', 'Rojnameya Kurdî ya pêşîn kîjan navî hildigire?', 'Kürdistan', 'Hawar', 'Azadiya Welat', 'Rojnameya Nû', 'A', 'Kürdistan gazetesi, ilk Kürt gazetesi olarak basın tarihinde özel bir yere sahiptir.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2246'),
    ('88cb52dd-ad38-4740-bdd7-df64ef84bc44'::uuid, 'ku-kmr', 'Kovara Hawar bi taybetî bi kîjan tevkariyê tê bibîranîn?', 'Latin temelli Kürt alfabesinin yaygınlaşması', 'Birçok yazarın yurt dışında üretmesi nedeniyle', 'Modern dönemde roman/gazete gibi türlerin gelişmesi', 'Sözlü anlatı ve ezgili hikâye aktarımı', 'A', 'Hawar çevresi, Latin temelli Kürt alfabesinin standartlaşması ve modern Kurmancî yazısı açısından önemlidir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2248'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Di çanda Kurdî de zêmar bi giştî xwedî kîjan fonksiyonê ne?', 'Misafirperverlik ve ilişki kurma isteğini', 'Acıyı, kaybı ve toplumsal hafızayı aktarmak', 'Bahar, yenilenme ve özgürlük/direniş', 'İranlılar ve birçok halk (Nevruz olarak)', 'B', 'Ağıtlar, bireysel yasın yanında toplumsal olayların ve kolektif acının hafızasını taşır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2261'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Di pêjgeha Kurdî de dolma/yaprax bi awayekî giştî çi ye?', 'İç harçla doldurulan sebze veya yaprak yemeği', 'Acıyı, kaybı ve toplumsal hafızayı aktarmak', 'Kültürel aidiyet ve coğrafi hafızayı', 'Özgün dini-kültürel topluluk ve tarihsel travmalar', 'A', 'Kürt mutfağında dolma veya yaprax, yaprak ve sebzelerin pirinçli/etli harçla doldurulmasıyla yapılır.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2266'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Li ser sifreyên kurdî parvekirina xwarinê bi sêniya mezin an pêşkêşiya hevpar çi xurt dike?', 'Topluluk ve aile bağlarını', 'Tam bireysel izolasyonu', 'Yemek yasağını', 'Sessiz sınav düzenini', 'A', 'Ortak sunum ve paylaşım, aile, komşuluk ve misafirlik ilişkilerini güçlendiren kültürel pratiklerdir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2270'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Vexwarina ji cureyê Dew/doogh bi kîjan madeya sereke re têkildar e?', 'Yoğurt/ayran', 'Kahve likörü', 'Sadece limon kabuğu', 'Mısır unu', 'A', 'Dew/doogh, yoğurt temelli ferahlatıcı bir içecek geleneğiyle ilişkilidir.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2271'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Di xwarinên kurdî de “nan” çi îfade dike?', 'Anne', 'genim', 'Ekmek', 'Irak', 'C', 'Nan, Kürtçede ekmek anlamına gelen temel kelimedir.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2273'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Cihêrengiya xwarinên herêmî yên kurdî çima nikare bibe yek rêçeteyeke standard?', 'Resmi arşivlerde görünmeyen deneyimleri ve hafızayı kaydedebildiği için', 'Sosyal örgütlenme, güvenlik, üretim ve siyasal ilişki ağı', 'Müslüman çoğunluk yanında Ezidi, Alevi, Yarsanî/Ehl-i Hak ve başka inanç toplulukları da vardır', 'Bölge, lehçe, iklim, tarım ve komşu mutfaklarla etkileşim farklı olduğu için', 'D', 'Kürt coğrafyası geniş olduğu için malzemeler ve tarif adları bölgeden bölgeye değişebilir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2276'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Êzidî di erdnîgariya çandî ya kurdî de bi taybetî bi kîjan sernavî têne bibîranîn?', 'Acıyı, kaybı ve toplumsal hafızayı aktarmak', 'İranlılar ve birçok halk (Nevruz olarak)', 'Özgün dini-kültürel topluluk ve tarihsel travmalar', 'Sosyal örgütlenme, güvenlik, üretim ve siyasal ilişki ağı', 'C', 'Ezidiler, Kürtçe konuşan/kimliklenen topluluklar arasında özgün inanç yapıları ve yakın dönem travmalarıyla öne çıkar.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2304'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Di nasnameya kurdî de ziman çima xwedî girîngiyeke navendî ye?', 'Farklı halkların eşitlik ve barış içinde ortak yaşamını', 'İç harçla doldurulan sebze veya yaprak yemeği', 'Kültürel hafıza, edebiyat, sözlü anlatı ve aidiyet taşıdığı için', 'Bölge, lehçe, iklim, tarım ve komşu mutfaklarla etkileşim farklı olduğu için', 'C', 'Dil, dengbêjlikten edebiyata ve günlük yaşama kadar kültürel hafızanın ana taşıyıcılarındandır.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2305'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Di civaka kurdî de avahiyên eşîrî di dîrokê de xwedî kîjan fonksiyonê bûne?', 'Tavuk ve pirinçle yapılan geleneksel yemek', 'Dil, kültür, yayıncılık, dayanışma ve kimlik aktarımı', 'İç harçla doldurulan sebze veya yaprak yemeği', 'Sosyal örgütlenme, güvenlik, üretim ve siyasal ilişki ağı', 'D', 'Aşiret yapıları tarihsel olarak sosyal dayanışma ve siyasal otorite ağlarının bir parçası olmuştur.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2307'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Fêrbûna navên cihan ên kurdî di sepanekê de çi xurt dike?', 'Kültürel aidiyet ve coğrafi hafızayı', 'Kullanıcıyı tamamen yanıltmayı', 'Dil görünürlüğünü azaltmayı', 'Soruları anlamsızlaştırmayı', 'A', 'Yer adları, coğrafyayı yalnızca harita değil, hafıza ve kimlik alanı olarak da öğretir.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2312'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Di sepaneke fêrbûnê ya wek ZanKurd de forma herî kêrhatî ya banka pirsan kîjan e?', 'Geçmiş zamanlı geçişli fiillerde', 'Soranî ders kitaplarından oluşan metin korpusu', 'Bilginin doğrulanabilirliğini artırır', 'Kategori, seçenek, doğru cevap ve açıklama içeren yapı', 'D', 'Uygulama için kategori, seçenekler, cevap ve açıklama alanları veri tabanı veya CSV aktarımını kolaylaştırır.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2314'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Di bankeke pirsan de qada “etîket” ji bo kîjan karê teknîkî ye?', 'Kısa açıklama ve doğru cevabın nedeni', 'Kategori, seçenek, doğru cevap ve açıklama içeren yapı', 'Arama, filtreleme ve kişiselleştirilmiş tekrar sistemi kurmaya', 'Kavram, tarih, kurum ve haklar üzerinden nesnel bağlam vermek', 'C', 'Etiketler, uygulamada kategori içi filtreleme ve zayıf konu tekrarları için kullanılabilir.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2322'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Di banka pirsan de pirsên siyaseta rojane çima divê bi rêkûpêk bêne nûkirin?', 'Kullanıcının sadece ezber değil, bağlam öğrenmesini sağladığı için', 'Kaynak, telif ve temsil doğruluğuna dikkat etmek', 'Merkezî Kürtçe/Soranî için konuşma korpusu ve tanıma sistemi', 'Parti adları, süreçler, hukuki statüler ve barış görüşmeleri zamanla değişebildiği için', 'D', '2025-2026 barış ve silahsızlanma tartışmaları gibi konular güncel gelişmelere bağlıdır; düzenli kaynak kontrolü gerekir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2324'),
    ('9e36450b-e6d6-412e-9279-5b48cd1386ff'::uuid, 'ku-kmr', 'Di slogana "Jin, jiyan, azadî" de "jiyan" tê çi wateyê?', 'Yaşam', 'Kadın', 'Onur', 'Özgürlük', 'A', 'Slogan "kadın (jin), yaşam (jiyan), özgürlük (azadî)" anlamına gelir.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2328'),
    ('9e36450b-e6d6-412e-9279-5b48cd1386ff'::uuid, 'ku-kmr', 'Sê tewereyên bingehîn ên Demokratik konfederalizmin kîjan in?', 'Kadın özgürlüğü, ekoloji ve demokrasi', 'Piyasa, mülkiyet ve rekabet', 'Sanayileşme, kalkınma ve refah', 'Ulus, bayrak ve vatan', 'A', 'Paradigmanın temel eksenleri kadın özgürlüğü, ekolojik toplum ve taban demokrasisidir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2329'),
    ('5e60bd93-f45a-4510-b8bd-9bb1f070fe03'::uuid, 'ku-kmr', 'Demokrasiya radîkal bi kîjan aliyê xwe ji demokrasiya temsîlî ya klasîk vediqete?', 'Kararları teknokratlara bırakır', 'Temsilcilere tam yetki devreder', 'Tabandan doğrudan ve sürekli katılımı önceler', 'Yalnızca referandumla yönetir', 'C', 'Radikal demokrasi, kararları seçilmişlere devretmek yerine tabandan doğrudan ve sürekli katılımı esas alır.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2336'),
    ('2f74083f-935b-4f75-bad4-b452f48370df'::uuid, 'ku-kmr', 'Ji cihê ku dengbêj lê dicivin û distirên re çi tê gotin?', 'Sûriye', 'Şarkı', 'Meydan', 'Dîwan', 'D', 'Dengbêjlerin toplanıp sırayla icra ettiği ortama dîwan (dîwana dengbêjan) denir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2349'),
    ('51f8811b-e9b6-4933-95d1-906be4df62bf'::uuid, 'ku-kmr', '"Hewlêr" navê Kurdî yê kîjan bajarî ye?', 'Musul', 'Süleymaniye', 'Kerkük', 'Erbil', 'D', 'Hewlêr, Irak Kürdistan Bölgesi''nin merkezi Erbil''in Kürtçe adıdır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2376'),
    ('2f74083f-935b-4f75-bad4-b452f48370df'::uuid, 'ku-kmr', '"Erbane" kîjan cureyê amûrê ye?', 'Telli', 'Vurmalı', 'Yaylı', 'Üflemeli', 'B', 'Erbane (def), çerçeveli/zilli bir vurmalı çalgıdır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2381'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Ji çîrok û serpêhatiyên ku zivistanan têne vegotin re bi Kurmancî bi giştî çi tê gotin?', 'Ekmek', 'Amca', 'Çîrok', 'Gelin', 'C', '"Çîrok" masal/hikâye demektir; stran ve kilam müzikle, govend ise dansla ilgilidir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2388'),
    ('88cb52dd-ad38-4740-bdd7-df64ef84bc44'::uuid, 'ku-kmr', 'Kovara "Hawar" ya ku beşdarî kurdiya nûjen kiriye li kîjan bajarî derketiye?', 'Şam', 'Tahran', 'İstanbul', 'Bağdat', 'A', 'Hawar dergisi, Celadet Alî Bedirxan tarafından Şam''da (Suriye) yayımlanmıştır.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2406'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', '"Agir" tê çi wateyê?', 'Eski', 'Elma', 'Ekmek', 'Ateş', 'D', '''Agir'' → Ateş.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2417'),
    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', 'Kurê Mistefa Barzanî yê ku serokatiya KDPê kiriye kî ye?', 'Qazi Muhammed', 'Simko Şikak', 'Mesud Barzani', 'Celal Talabani', 'C', 'Mesud Barzani, Mustafa Barzani''nin oğludur ve KDP liderliği yapmıştır.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2429'),
    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', 'Komara Mahabadê di kîjan salê de hatiye damezrandin?', '1946', '1991', '1923', '1960', 'A', 'Mahabad Cumhuriyeti 1946''da, bugünkü İran sınırları içinde kurulmuştur.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2430'),
    ('51f8811b-e9b6-4933-95d1-906be4df62bf'::uuid, 'ku-kmr', '"Dîcle" navê kîjan çem e?', 'Fırat', 'Murat', 'Aras', 'Dicle', 'D', '"Dîcle", Dicle Nehri''nin Kürtçe/yerel adıdır.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2436'),
    ('5e60bd93-f45a-4510-b8bd-9bb1f070fe03'::uuid, 'ku-kmr', 'Di modela xweseriya demokratîk de biryar bi giranî li ku têne girtin?', 'Yerel meclis ve komünlerde', 'Uluslararası mahkemede', 'Tek bir liderde', 'Sadece merkezi hükümette', 'A', 'Demokratik özerklikte kararlar, yerel meclis ve komünler aracılığıyla tabandan alınır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2443'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', '"Newroz" ji kîjan du peyvan pêk tê?', 'Masal/hikâye anlatan kişi', 'el sanatı ile ilişkilidir', '"Nû" (yeni) + "roj" (gün)', 'Manevi akrabalık (sünnet)', 'C', 'Newroz, "nû" (yeni) ve "roj" (gün) sözcüklerinden oluşur: yeni gün.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2451'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Di çanda herêmê de heyîna efsaneyî ya bi motîfa mar a berbelav kîjan e?', 'Şahmaran', 'Kanatlı at efsanesi', 'Deniz kızı efsanesi', 'Dev kuş efsanesi', 'A', 'Şahmaran, yarı insan yarı yılan biçiminde tasvir edilen, bölgede yaygın efsanevi bir varlıktır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2452'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', '"Cejna Newrozê" tê çi wateyê?', 'Yas günü', 'Hasat günü', 'Kurban bayramı', 'Newroz bayramı', 'D', '"Cejna Newrozê" Newroz bayramı demektir (cejn = bayram).', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2455'),
