    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', '"Şerefname" di bingehê de çi vedibêje?', 'Haçlı seferlerine karşı mücadele', 'Kürt hanedan ve beyliklerinin tarihini', 'Aşiretlerden oluşturulan süvari birlikleri', 'Med İmparatorluğu (Pers öncesi)', 'B', 'Şerefname, Kürt hanedanlarının ve beyliklerinin tarihini anlatan ilk kapsamlı eserdir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2459'),
    ('51f8811b-e9b6-4933-95d1-906be4df62bf'::uuid, 'ku-kmr', '"Semsûr" navê Kurdî yê kîjan bajarî ye?', 'Adıyaman', 'Antep', 'Maraş', 'Malatya', 'A', '"Semsûr", Adıyaman şehrinin Kürtçe adıdır.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2464'),
    ('51f8811b-e9b6-4933-95d1-906be4df62bf'::uuid, 'ku-kmr', 'Herêma Hewramî (Hawraman) di kêleka sînorê kîjan du welatan de ye?', 'İran-Türkiye', 'Irak-Suriye', 'Türkiye-Suriye', 'İran-Irak', 'D', 'Hawraman (Hewramî) bölgesi, İran ile Irak sınır kuşağında, dağlık bir Kürt yöresidir.', NULL, NULL, 5, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2467'),
    ('2f74083f-935b-4f75-bad4-b452f48370df'::uuid, 'ku-kmr', '"Govend" di bingehê de çalakiyeke çawa ye?', 'Şiir okuma', 'Bireysel şarkı', 'Tiyatro gösterisi', 'Toplu halk dansı', 'D', 'Govend, el ele tutuşularak oynanan toplu bir halk dansıdır.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2468'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Sê rengên bingehîn ên li ser ala Kurdî kîjan in?', 'Siyah, kırmızı ve sarı', 'Mavi, beyaz ve kırmızı', 'Yeşil, sarı ve mor', 'Kırmızı, beyaz ve yeşil', 'D', 'Kürt bayrağında kırmızı, beyaz ve yeşil renkler ile ortada bir güneş bulunur.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2481'),
    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', 'Ji qetlîamên ku Êzidî di dîrokê de rastî wan hatine re bi zimanê wan çi tê gotin?', 'Hawar', 'Mahabad', 'Farsça', 'Ferman', 'D', 'Êzidîler, maruz kaldıkları katliamları kendi dillerinde "ferman" olarak adlandırır.', NULL, NULL, 5, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2486'),
    ('51f8811b-e9b6-4933-95d1-906be4df62bf'::uuid, 'ku-kmr', 'Bajarên wek Amed, Riha ve Mêrdîn li kîjan herêma dîrokî cih digirin?', 'Erbil (Hewlêr)', 'Maraş (Kahramanmaraş)', 'Nuh''un gemisi (tufan)', 'Yukarı Mezopotamya', 'D', 'Bu şehirler, Dicle-Fırat arasındaki Yukarı Mezopotamya bölgesinde yer alır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2497'),
    ('2f74083f-935b-4f75-bad4-b452f48370df'::uuid, 'ku-kmr', 'Amûrên bi şêwaza "Mey" dikevin kîjan komê?', 'Telli', 'Üflemeli', 'Yaylı', 'Vurmalı', 'B', 'Mey, kamıştan yapılan üflemeli bir çalgıdır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2499'),
    ('5e60bd93-f45a-4510-b8bd-9bb1f070fe03'::uuid, 'ku-kmr', 'Di têgihiştina "Demokratik ulus" de gelên cuda çawa bi hev re dijîn?', 'Eşit ve gönüllü birliktelikle', 'Tam bir ayrışmayla', 'Katı bir hiyerarşiyle', 'Birinin diğerine asimilasyonuyla', 'A', 'Demokratik ulus, farklı halk ve inançların eşit, gönüllü ve çoğulcu birlikteliğini esas alır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2502'),
