    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', '"Çiya" tê çi wateyê?', 'Ova', 'Nehir', 'Göl', 'Dağ', 'D', '"Çiya" dağ demektir (ör. Çiyayê Agirî = Ağrı Dağı).', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2538'),
