    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', 'Selahaddînê Eyûbî li kîjan bajarî ji dayik bûye?', 'Bağdat', 'Kahire', 'Tikrit', 'İstanbul', 'C', 'Selahaddin Eyyubi, bugünkü Irak''ta yer alan Tikrit''te doğmuştur.', NULL, NULL, 5, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2668'),
    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', 'Eyyubiyan kîjan bajaran ji bo demek dirêj wek navend bi kar anîne?', 'Pekin ve Tokyo', 'Madrid ve Lizbon', 'Roma ve Atina', 'Kahire ve Şam', 'D', 'Eyyubiler, ağırlıkla Kahire ve Şam''ı merkez edinmiştir.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2669'),
    ('88cb52dd-ad38-4740-bdd7-df64ef84bc44'::uuid, 'ku-kmr', 'Cigerxwîn berhemên xwe bi kîjan zimanî nivîsandiye?', 'Kürtçe (Kurmancî)', 'Siyabend û Xecê', 'dest jî rû dişo', 'Dîwana xwe ya klasîk', 'A', 'Cigerxwîn, şiirlerini Kürtçe (Kurmancî) yazmıştır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2674'),
    ('9e36450b-e6d6-412e-9279-5b48cd1386ff'::uuid, 'ku-kmr', '"Ekolojik toplum" ji civaka pîşesaziyê bi kîjan aliyê ve cuda dibe?', 'Doğayı yalnızca sömürü nesnesi olarak görmemesiyle', 'Toplumsal bilinç ve özgür düşünceyi geliştirmeyi', 'Dünya çapında kadın özgürlüğü sembolü olmuştur', 'Toplumun kendini koruma ve örgütleme hakkını', 'A', 'Ekolojik toplum, doğayı sınırsız sömürülecek bir nesne olarak görmemesiyle sanayi toplumundan ayrılır.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2682'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Serokatiya olî ya civaka Êzidî bi kevneşopî ji aliyê kê ve tê meşandin?', 'Kına (hene) gecesi', 'Mîr ve Baba Şeyh', 'çîrokan vedibêje', 'Baharatlı pirinç', 'B', 'Êzidî toplumunda dinî-toplumsal önderlik geleneksel olarak Mîr ve Baba Şeyh tarafından yürütülür.', NULL, NULL, 5, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2692'),
    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', 'Peymana ku şûna Sevrê girt û statuya Kurdan tê de tune kîjan e?', 'Lozan (1923)', 'Dîcle û Ferat', 'Sünni İslam', '19. yüzyıl', 'A', '1923 Lozan Antlaşması, Sevr''in yerine geçmiş ve Kürtlere dair bir statü içermemiştir.', NULL, NULL, 5, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2696'),
    ('88cb52dd-ad38-4740-bdd7-df64ef84bc44'::uuid, 'ku-kmr', 'Mehmed Uzun berhemên xwe bi piranî bi kîjan zimanî nivîsandiye?', 'Doğa ve kuşlar', 'Kürtçe (Kurmancî)', 'Yazar ve aydın', '15-18. yüzyıllar', 'B', 'Mehmed Uzun, İsveç''te yaşamasına rağmen eserlerini ağırlıkla Kürtçe (Kurmancî) yazmıştır.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2699'),
    ('51f8811b-e9b6-4933-95d1-906be4df62bf'::uuid, 'ku-kmr', '"Çiyayê Sîpan" nêzîkî kîjan golê ye?', 'Van Gölü', 'Eğirdir Gölü', 'Tuz Gölü', 'Beyşehir Gölü', 'A', 'Çiyayê Sîpan (Süphan Dağı), Van Gölü''nün kuzeyinde yer alır.', NULL, NULL, 5, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2705'),
    ('5e60bd93-f45a-4510-b8bd-9bb1f070fe03'::uuid, 'ku-kmr', 'Di paradîgmayê de mafê "Anadil" herî zêde bi çi re tê têkildarkirin?', 'Yerel/bölgesel düzeyde', 'Kültürel varoluş ve kimlik', 'Yerel komünlerden üst meclislere', 'Kadın dayanışması ve özgürlüğü', 'B', 'Anadil hakkı, kültürel varoluş ve kimliğin sürdürülmesiyle ilişkilendirilir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2710'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Di çanda gelêrî ya Kurdî de girîngiya ku ji çiyayan re tê dayîn herî zêde bi çi tê ravekirin?', 'İranlılar ve birçok halk (Nevruz olarak)', 'Tarih boyunca dağlık coğrafyada yaşamayla', 'Zulme karşı direniş ve yeniden doğuş', 'Halay çekilir ve ateşin üstünden atlanır', 'B', 'Kürtlerin dağlara verdiği önem, tarih boyunca dağlık bir coğrafyada yaşamalarıyla ilişkilidir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2724'),
    ('074584d5-9db4-4406-8545-5302e994021b'::uuid, 'ku-kmr', 'Selahaddînê Eyûbî piştî kîjan şerî Qudsê vegerand?', 'Hıttin Savaşı (1187)', 'Ankara Savaşı', 'Çanakkale Savaşı', 'Malazgirt Savaşı', 'A', 'Selahaddin Eyyubi, 1187 Hıttin Savaşı''nın ardından Kudüs''ü geri almıştır.', NULL, NULL, 5, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2727'),
    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Di Kurmancî de "nivîsîn" tê çi wateyê?', 'Yazmak', 'Çizmek', 'Okumak', 'Silmek', 'A', '"Nivîsîn" yazmak demektir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2749'),
