    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Di Êzidîtiyê de kevneşopiya duakirina ber bi rojê ve çi nîşan dide?', 'Işığa/güneşe verilen kutsallığı', 'Melek Tavus ve ışık/güneş motifi', 'gündelik kültür ile ilişkilidir', 'toplumsal bağları güçlendirme', 'A', 'Êzidî geleneğinde güneşe/ışığa verilen kutsallık, ibadet biçimlerine de yansır.', NULL, NULL, 4, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2782'),
    ('88cb52dd-ad38-4740-bdd7-df64ef84bc44'::uuid, 'ku-kmr', 'Hilgirên herî girîng ên wêjeya devkî ya kurdî kî ne?', 'Askerler', 'Denizciler', 'Tüccarlar', 'Dengbêjler', 'D', 'Kürt sözlü edebiyatının en önemli taşıyıcıları dengbêjlerdir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2787'),
    ('51f8811b-e9b6-4933-95d1-906be4df62bf'::uuid, 'ku-kmr', '"Euphrates" navê din ê kîjan çem e?', 'Aras', 'Ren', 'Dicle', 'Fırat', 'D', '"Euphrates", Fırat Nehri''nin (uluslararası) adıdır.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2790'),
