    ('5e60bd93-f45a-4510-b8bd-9bb1f070fe03'::uuid, 'ku-kmr', '"Demokratik çözüm" kîjan nirxan pêşanî dike?', 'Sınır, ordu ve bayrağı', 'Eşitlik, özgürlük ve barışı', 'Hiyerarşi, zenginlik ve gücü', 'Rekabet, kâr ve mülkiyeti', 'B', 'Demokratik çözüm; eşitlik, özgürlük ve barış değerlerini önceler.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2823'),
    ('2f74083f-935b-4f75-bad4-b452f48370df'::uuid, 'ku-kmr', '"Kilam, stran ve lawik" bi hevpariyê wek kî tê naskirin?', 'ji bo pitikan', 'Kürt ezgi türleri', 'Sözlü kültürel miras', 'bê amûr (a capella)', 'B', 'Kilam, stran ve lawik, Kürt sözlü-müzikal geleneğinin ezgi türleridir.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_2825'),
