    ('5e60bd93-f45a-4510-b8bd-9bb1f070fe03'::uuid, 'ku-kmr', 'Ji bo ''ademi merkeziyetçilik'' ravekirina herî dirust kîjan e?', 'Hem reel sosyalizmi hem kapitalizmi olduğu gibi', 'gücün tek merkezden yerel birimlere dağıtılması', 'protesto, örgütlenme ve ifade özgürlüğü hakları', 'kaynakların ve hakların eşit paylaşılması ilkesi', 'B', '''ademi merkeziyetçilik'' → gücün tek merkezden yerel birimlere dağıtılması.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_12899'),
