    ('1943ced4-8f44-4e0b-8a88-c2a5a8af5284'::uuid, 'ku-kmr', 'Peyva ''file'' di Kurmancî de tê çi wateyê?', 'Rûpel', 'Dosya', 'Wêne', 'Stran', 'B', 'Di Kurmancî de ji bo ''dosya'' peyva ''peldank'' an ''dosya'' tê bikaranîn.', NULL, NULL, 3, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_curated_30009'),
