    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Wateya ''ji kerema xwe'' ''teşekkür ederim'' e?', 'Rast', 'Şaş', '-', '-', 'B', '''ji kerema xwe'' tê wateya ''lütfen''. ''Spas dikim'' tê wateya ''teşekkür ederim''.', NULL, NULL, 2, true, 'true_false', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_curated_30014'),
