    ('1d6eb56b-1fb1-4bfa-82c6-9b7e3437be94'::uuid, 'ku-kmr', 'Wateya ''şevbaş'' ''iyi akşamlar'' e?', 'Rast', 'Şaş', '-', '-', 'B', '''Şevbaş'' tê wateya ''iyi geceler''. ''Êvarbaş'' tê wateya ''iyi akşamlar''.', NULL, NULL, 3, true, 'true_false', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_curated_30018'),
    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Tiştoka ''Bi roj hevalê min e, bi şev hevalê dîwêr e'' bersiva wê çi ye?', 'Sol / Pêlav', 'Çire / Fener', 'Mifta / Kilît', 'Dermên', 'A', 'Ev tiştokeke kurdî ya gelêrî ye, bersiva wê ''sol'' (pêlav) e.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_curated_30024'),
