    ('193daac4-d049-4c58-9b79-af22d6a14eb9'::uuid, 'ku-kmr', 'Tiştoka ''Heta jê nekirî mezin nabe'' bersiva wê çi ye?', 'Kolin / Çal', 'Dîwar', 'Dar', 'Rê', 'A', 'Ev tiştokeke zekayê ye, bersiva wê ''kolin'' an ''çal'' (çukur) e.', NULL, NULL, 2, true, 'multiple_choice', NULL, 'zankurd_offline_curated_2026_07_19', 'offline_curated_30029'),
