INSERT INTO public.questions(category_id, language_code, prompt, option_a, option_b, option_c, option_d, correct_option, explanation, explanation_ku, explanation_tr, difficulty, is_approved, question_type, image_url, source_url, source_reference)
SELECT n.*
FROM new_rows n
WHERE NOT EXISTS (
  SELECT 1 FROM public.questions q
  WHERE q.prompt = n.prompt AND q.category_id = n.category_id
);

UPDATE public.questions
SET option_a = 'Müslüman çoğunluk yanında Ezidi, Alevi, Yarsanî/Ehl-i Hak ve başka inanç toplulukları da vardır', option_b = 'Tek bir inanç dışında kimse yoktur', option_c = 'Hiçbir dini topluluk yoktur', option_d = 'Sadece Budist manastırlardan oluşur',
    correct_option = 'A', explanation = 'Kürt toplumları farklı ülkelerde Sünni, Alevi, Ezidi, Yarsanî/Ehl-i Hak ve diğer inanç gruplarını içeren çeşitlilik gösterir.', updated_at = now()
WHERE prompt = 'Kürt toplumunda dini çeşitlilik için en doğru ifade hangisidir?' AND correct_option <> 'A';

UPDATE public.questions
SET option_a = 'Kategori, seçenek, doğru cevap ve açıklama içeren yapı', option_b = 'Sadece boş satırlar', option_c = 'Sadece görsel dosya adları', option_d = 'Hiç cevap içermeyen metin',
    correct_option = 'A', explanation = 'Uygulama için kategori, seçenekler, cevap ve açıklama alanları veri tabanı veya CSV aktarımını kolaylaştırır.', updated_at = now()
WHERE prompt = 'ZanKurd gibi bir öğrenme uygulamasında soru bankasının en faydalı biçimi hangisidir?' AND correct_option <> 'A';

UPDATE public.questions
SET option_a = 'Otomatik düzeltme, arama, ses tanıma ve içerik önerisi geliştirme imkânı verir', option_b = 'Dil görünürlüğünü azaltır', option_c = 'Tüm içerikleri siler', option_d = 'Sadece yemek pişirir',
    correct_option = 'A', explanation = 'Korpus ve konuşma verisi gibi kaynaklar, arama, öneri, ses tanıma ve eğitim teknolojileri için temel oluşturur.', updated_at = now()
WHERE prompt = 'Kürtçe NLP çalışmalarının artması ZanKurd gibi uygulamalara nasıl katkı sağlar?' AND correct_option <> 'A';

UPDATE public.questions
SET option_a = 'Kaynak, telif ve temsil doğruluğuna dikkat etmek', option_b = 'Her görseli izinsiz almak', option_c = 'Alakasız görsel kullanmak', option_d = 'Tüm kültürü tek klişeye indirgemek',
    correct_option = 'A', explanation = 'Kültürel materyallerde telif, temsil ve bağlam doğruluğu kullanıcı güvenini artırır.', updated_at = now()
WHERE prompt = 'Uygulamada kültürel görseller kullanılırken en doğru yaklaşım hangisidir?' AND correct_option <> 'A';
